const { Storage } = require('@google-cloud/storage');
const path = require('path');

const storage = new Storage();

// Allowlist of permitted buckets - CONFIGURE THIS
const ALLOWED_BUCKETS = process.env.ALLOWED_BUCKETS 
  ? process.env.ALLOWED_BUCKETS.split(',') 
  : [];

// Maximum file size to serve (in bytes) - 100MB default
const MAX_FILE_SIZE = parseInt(process.env.MAX_FILE_SIZE || '104857600', 10);

// Allowed file extensions - CONFIGURE THIS
const ALLOWED_EXTENSIONS = process.env.ALLOWED_EXTENSIONS
  ? process.env.ALLOWED_EXTENSIONS.split(',')
  : ['.txt', '.pdf', '.jpg', '.jpeg', '.png', '.gif', '.json', '.csv', '.xml'];

function validateBucketName(bucketName) {
  if (!bucketName || typeof bucketName !== 'string') {
    return false;
  }
  
  // Check against allowlist
  if (!ALLOWED_BUCKETS.includes(bucketName)) {
    return false;
  }
  
  // Validate bucket name format (GCS naming rules)
  const bucketRegex = /^[a-z0-9][a-z0-9._-]{1,61}[a-z0-9]$/;
  return bucketRegex.test(bucketName);
}

function validateFilePath(filePath) {
  if (!filePath || typeof filePath !== 'string') {
    return false;
  }
  
  // Prevent path traversal attacks
  const normalized = path.normalize(filePath).replace(/\\/g, '/');
  
  // Check for path traversal patterns
  if (normalized.includes('..') || 
      normalized.startsWith('/') || 
      normalized.includes('//') ||
      normalized.includes('\0')) {
    return false;
  }
  
  // Check file extension
  const ext = path.extname(normalized).toLowerCase();
  if (!ALLOWED_EXTENSIONS.includes(ext)) {
    return false;
  }
  
  // Maximum path length
  if (normalized.length > 1024) {
    return false;
  }
  
  return normalized;
}

function getContentType(filePath) {
  const ext = path.extname(filePath).toLowerCase();
  const contentTypes = {
    '.txt': 'text/plain',
    '.pdf': 'application/pdf',
    '.jpg': 'image/jpeg',
    '.jpeg': 'image/jpeg',
    '.png': 'image/png',
    '.gif': 'image/gif',
    '.json': 'application/json',
    '.csv': 'text/csv',
    '.xml': 'application/xml'
  };
  return contentTypes[ext] || 'application/octet-stream';
}

exports.serveFile = async (req, res) => {
  // Set security headers
  res.set('X-Content-Type-Options', 'nosniff');
  res.set('X-Frame-Options', 'DENY');
  res.set('X-XSS-Protection', '1; mode=block');
  res.set('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
  
  // Only allow GET requests
  if (req.method !== 'GET') {
    res.status(405).send('Method Not Allowed');
    return;
  }
  
  try {
    // Extract and validate bucket name
    const bucketName = req.query.bucket;
    if (!validateBucketName(bucketName)) {
      console.warn('Invalid bucket name attempted:', bucketName ? 'REDACTED' : 'undefined');
      res.status(400).send('Invalid bucket name');
      return;
    }
    
    // Extract and validate file path
    const filePath = req.query.path;
    const validatedPath = validateFilePath(filePath);
    if (!validatedPath) {
      console.warn('Invalid file path attempted');
      res.status(400).send('Invalid file path');
      return;
    }
    
    // Get bucket and file reference
    const bucket = storage.bucket(bucketName);
    const file = bucket.file(validatedPath);
    
    // Check if file exists and get metadata
    const [exists] = await file.exists();
    if (!exists) {
      res.status(404).send('File not found');
      return;
    }
    
    const [metadata] = await file.getMetadata();
    
    // Validate file size
    const fileSize = parseInt(metadata.size, 10);
    if (fileSize > MAX_FILE_SIZE) {
      console.warn('File size exceeds limit:', fileSize);
      res.status(413).send('File too large');
      return;
    }
    
    // Set appropriate headers
    res.set('Content-Type', getContentType(validatedPath));
    res.set('Content-Length', metadata.size);
    res.set('Cache-Control', 'private, max-age=3600');
    res.set('Content-Disposition', `inline; filename="${path.basename(validatedPath)}"`);
    
    // Stream the file
    const readStream = file.createReadStream({
      validation: true // Enable CRC32C validation
    });
    
    readStream.on('error', (err) => {
      console.error('Stream error:', err.message);
      if (!res.headersSent) {
        res.status(500).send('Error streaming file');
      }
    });
    
    readStream.pipe(res);
    
  } catch (error) {
    console.error('Error serving file:', error.message);
    
    if (!res.headersSent) {
      if (error.code === 403) {
        res.status(403).send('Access denied');
      } else if (error.code === 404) {
        res.status(404).send('File not found');
      } else {
        res.status(500).send('Internal server error');
      }
    }
  }
};